/// Look up an editable item's official zh-Hans name by base id.
pub fn item_name(id: u32) -> Option<&'static str> {
    ITEM_DB.binary_search_by_key(&id, |&(k, _)| k).ok().map(|i| ITEM_DB[i].1)
}
